public void clean(Document dirtyDocument){
    Validate.notNull(dirtyDocument);

    // Handle Framesets
    Elements iframes = dirtyDocument.select("frameset > frame");
    for (Element el : iframes) {
        String urlStr = el.attr("longdesc");
        org.jsoup.nodes.Document.Element urlDocElm = new org.jsoup.nodes.Document(urlStr).getElementById("#f1");
        Element cloneFrame = Jsoup.parse(String.valueOf(urlDocElm)).getElementsByTag("body").first();

        el.after(cloneFrame);
        el.remove();
    }


      Deque<Node> stack = new ArrayDeque<>();
    stack.push(dirtyDocument.html());

    while(!stack.isEmpty()){
        Node node=stack.pop();
        if(node instanceof TextNode && ((TextNode) node).parent() instanceof HtmlNode ){
            continue;
        }else if (!(node instanceof Comment)){

               if (((Element)node).hasAttr("style")){
                 ((Element)node).removeAttr("style");
                }
             if (((Element)node).hasAttr("class")){
                  ((Element)node).removeAttr("class");
              }
             if (((Element)node).hasAttr("id")){
                  ((Element)node).removeAttr("id");
              }

        }
        if(node instanceof Element){
            List<Attribute> attributes=new ArrayList<>();
           attributes.addAll(((Element) node).attributes().asList());
           for (Attribute attribute : attributes){

               if (attribute.isUrl()|| attribute.isMediaQuery())continue;

               else ((Element) node).removeAttr(attribute.getKey());
           }

        }
        if(node instanceof Document){
            for (int i = 0;i < ((Document) node).childNodesCount(); i++){
                stack.push(((Document) node).childNode(i));
            }
        }
        if(node instanceof HtmlNode){
            stack.push(((HtmlNode) node).childNode(0));
        }

    }


}

